args.query:
SELECT u.Id, u.FirstName, u.LastName, u.Email
FROM "User" u
WHERE REPLACE(u.Id,'#','') IN (
  SELECT REPLACE(OwnerId,'#','') FROM sales_pipeline.Lead WHERE REPLACE(Id,'#','')='00QWt0000089AekMAE'
)
LIMIT 5;

